const a=r=>String(r??"").toLowerCase().replace(/[^a-z0-9]+/g," ").trim();function f(r,s){const e=Array.from({length:s.length+1},(t,l)=>l);for(let t=1;t<=r.length;t+=1){let l=e[0];e[0]=t;for(let n=1;n<=s.length;n+=1){const c=e[n];e[n]=Math.min(e[n]+1,e[n-1]+1,l+(r[t-1]===s[n-1]?0:1)),l=c}}return e[s.length]}function m(r,s){const e=a(r);if(!e)return!0;const t=e.split(" ");return s.some(l=>{const n=a(l);if(!n)return!1;if(n.includes(e)||e.includes(n))return!0;const c=n.split(" ");return t.every(o=>c.some(i=>{if(i.includes(o)||o.includes(i))return!0;const u=o.length>=7?2:o.length>=4?1:0;return f(o,i)<=u}))})}export{m};
